import sys
readline = sys.stdin.readline

def main():
    n, s = map(int, readline().split())
    a = list(map(int, readline().split()))
    dp = [[0] * (s + 1) for _ in range(n + 1)]
    dp[0][0] = 1
    for i in range(n):
        for j in range(s + 1):
            dp[i + 1][j] += dp[i][j]
            if j + a[i] <= s:
                dp[i + 1][j + a[i]] += dp[i][j]
    print(sum(dp[n]) % 998244353)

if __name__ == '__main__':
    main()
